fixed_code:
macro_rules! sum_accumulate {
    ($iter:expr) => {{
        let mut acc = 0;
        for x in $iter {
            acc += x;
        }
        acc
    }};
}

fn main() {
    let data = vec![1, 2, 3];
    println!("Sum: {}
", sum_accumulate!(data.iter().flat_map(|x| std::iter::once(*x * 2))));
}
